    for i in range(n):
        prev = nums[n - 1] if i == 0 else nums[i - 1]
        next_val = nums[i + 1] if i < n - 1 else nums[0]
        if nums[i] <= prev or nums[i] <= next_val:
            # Need to increase nums[i] to be strictly greater than both
            cost[i] = max(prev, next_val) - nums[i] + 1
        else:
            cost[i] = 0

    # Use a sliding window to find the minimum sum of k consecutive peaks
    min_operations = float('inf')
    for i in range(n):
        window_sum = sum(cost[i:i + k])
